import express from "express";
import path from "path";
import { createServer as createViteServer } from "vite";
import { GoogleGenAI, HarmCategory, HarmBlockThreshold } from "@google/genai";
import dotenv from "dotenv";

dotenv.config();

// Lazy helper to get GoogleGenAI client with fresh API key
function getAiClient() {
  const apiKey = process.env.GEMINI_API_KEY;
  if (!apiKey) {
    throw new Error("GEMINI_API_KEY is not defined in process.env");
  }
  return new GoogleGenAI({
    apiKey: apiKey,
    httpOptions: {
      headers: {
        'User-Agent': 'aistudio-build',
      }
    }
  });
}

async function startServer() {
  const app = express();
  const PORT = 3000;

  app.use(express.json());

  // API routes
  app.post("/api/summarize", async (req, res) => {
    try {
      const { biography } = req.body;
      console.log("[API /api/summarize] Received request for biography length:", biography?.length);
      
      if (!biography || typeof biography !== "string" || !biography.trim()) {
        return res.status(400).json({ error: "Биография не заполнена или некорректна." });
      }

      if (!process.env.GEMINI_API_KEY) {
        console.error("[API /api/summarize] GEMINI_API_KEY is not defined in process.env");
        return res.status(500).json({ error: "GEMINI_API_KEY не настроен на сервере." });
      }

      const ai = getAiClient();
      console.log("[API /api/summarize] Calling ai.models.generateContent with model gemini-3.5-flash");

      const response = await ai.models.generateContent({
        model: "gemini-3.5-flash",
        contents: biography,
        config: {
          systemInstruction: 
            "Ты — опытный детектив полиции и архивариус 1940-х годов. " +
            "Твоя задача — сжать/ужать предоставленную биографию подозреваемого/преступника. " +
            "КРИТИЧЕСКИ ВАЖНО: Абсолютно избегай детального или графического описания жестокости, убийств, пыток, крови и любого насилия. " +
            "Если в оригинальном тексте есть упоминания о насилии, ОБЯЗАТЕЛЬНО перефразируй их в максимально сухие, нейтральные, казенные, официальные " +
            "и размытые криминалистические формулировки (например: «совершил тяжкие преступления», «устранил оппонентов», «обвиняется в правонарушениях», " +
            "«вел незаконную деятельность» вместо описания жестоких подробностей). " +
            "Текст должен быть написан в мрачном нуарном стиле изложения на русском языке. Длина итогового текста должна составлять до 500 символов (примерно 4-5 информативных предложений), чтобы сохранить больше ключевых деталей биографии, оставаясь лаконичным.",
          safetySettings: [
            { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_NONE },
            { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_NONE },
            { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_NONE },
            { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_NONE },
            { category: HarmCategory.HARM_CATEGORY_CIVIC_INTEGRITY, threshold: HarmBlockThreshold.BLOCK_NONE }
          ]
        }
      });

      console.log("[API /api/summarize] Gemini response keys:", Object.keys(response || {}));

      // Check if prompt was blocked - if so, generate a safe backup summary instead of returning 400 error!
      if (response.promptFeedback && response.promptFeedback.blockReason === "PROHIBITED_CONTENT") {
        console.warn("[API /api/summarize] Content was blocked due to PROHIBITED_CONTENT. Returning fallback summary instead of error.");
        return res.json({ 
          summary: "Материалы дела классифицированы Департаментом. Субъект обвиняется в нарушении федерального законодательства, активном участии в организованной преступности и ведении подпольной деятельности. Подробные насильственные эпизоды изъяты из официального отчета в интересах следственного делопроизводства."
        });
      }
      
      // Extraction with fallback methods
      let summary = response.text;
      
      if (!summary && response.candidates && response.candidates[0]) {
        console.log("[API /api/summarize] response.text was empty, checking candidates...");
        const candidate = response.candidates[0];
        
        // If candidate was stopped due to safety concern
        if (candidate.finishReason === "SAFETY") {
          console.warn("[API /api/summarize] Candidate finishReason is SAFETY, returning fallback summary.");
          return res.json({
            summary: "Досье классифицировано Администрацией Департамента. Субъект замешан в организованной криминальной деятельности, рэкете и нарушении федерального порядка. Часть оперативной информации изъята во избежание разглашения особо чувствительных деталей дела."
          });
        }

        const parts = candidate.content?.parts;
        if (parts && parts[0]) {
          summary = parts[0].text;
          console.log("[API /api/summarize] Extracted biography from candidate parts[0].text");
        }
      }

      if (!summary) {
        console.warn("[API /api/summarize] No text generated, possibly blocked. Returning safe default summary.");
        return res.json({
          summary: "Материалы подозреваемого занесены в архив в закрытом режиме. Субъект проходит главным фигурантом по делу синдиката. Дальнейшие оперативно-следственные действия осуществляются под грифом 'Секретно'."
        });
      }

      const trimmedSummary = summary.trim();
      console.log("[API /api/summarize] Successfully summarized biography to length:", trimmedSummary.length);
      res.json({ summary: trimmedSummary });
    } catch (error: any) {
      console.error("[API /api/summarize] Gemini summarize error:", error);
      
      // If error message indicates safety, block, or content, gracefully fallback instead of failing
      const errString = String(error?.message || "").toLowerCase();
      if (errString.includes("safety") || errString.includes("block") || errString.includes("candidate") || errString.includes("prohibited")) {
        console.log("[API /api/summarize] Safety/Block error detected, sending fallback response.");
        return res.json({
          summary: "Дело заархивировано с купюрами. Обвиняемый замешан в теневых криминальных операциях, рэкетирских заговорах и подрыве устоев. Подробности инцидентов подвергнуты цензуре в соответствии с параграфом Б-41 Уголовного Кодекса США."
        });
      }

      res.status(500).json({ error: error?.message || "Внутренняя ошибка сервера при обработке ИИ." });
    }
  });

  // Vite middleware for development
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on port ${PORT}`);
  });
}

startServer();
